from abc import ABC, abstractmethod
from domain.note import Note   # only domain types

class NoteRepository(ABC):
    @abstractmethod
    async def save(self, note: Note) -> None: ...
    @abstractmethod
    async def get(self, note_id: NoteId) -> Note | None: ...
# small, cohesive port expressed entirely in domain terms; no Session, no ORM.
